@ARTICLE{10.1111/obr.70039,
	author = {Garcia N(1) and Mellergaard M(2)(3) and Salomon C(4) and Sepulveda P(5)(6) and Kristensen P(7) and Handberg A(2)(3).},
	title = {CD36 and Its Role in Obesity.},
	journal = {Obes Rev},
	year = {2026},
	abstract = {Obesity is understood as a condition driven by interactions between genetics and environmental factors. The role of CD36 in the regulation of lipid metabolism and ectopic fat accumulation emerges as a key area of interest. This review presents CD36 not only as a crucial facilitator of fatty acid uptake but also as a regulator of how and where excess lipids are stored. Ectopic fat accumulation-lipid deposition in non-adipose tissues such as the liver, muscle, and pancreas-is linked to obesity-related complications, including metabolic dysfunction-associated steatotic liver disease (MASLD) and cardiovascular risk. Through CD36, tissues that normally play minor roles in lipid storage become overloaded, leading to metabolic dysfunction. We offer a fresh perspective on the adipose tissue expandability hypothesis, positioning CD36 as a regulator of adipose tissue's capacity to store lipids. Possibly, once adipose tissue reaches its expansion limit, CD36-mediated mechanisms drive the spillover of lipids into ectopic sites, exacerbating obesity complications. This insight offers a transformative view of CD36 as a player in the metabolic tipping point between healthy fat storage and pathogenic fat deposition. The connection between CD36 and extracellular vesicles (EVs) hints at a broader network of inter-tissue communication that could further amplify ectopic fat accumulation. Finally, we list evidence showing how CD36 genetics are related to the predisposition to develop and manage obesity. By understanding the role of CD36 in fat storage regulation, new personalized therapeutic strategies may emerge, targeting its pathways to prevent or reverse the metabolic damage caused by ectopic fat.},
	doi = {10.1111/obr.70039},
	pmid = {41344388 [Indexed for MEDLINE]},
	note = {PMC12926625}
}

